rules.rule_text:
private rule _fat
{
	meta:
		reference = "http://pastebin.com/2W0tyUAF"
		reference2 = "https://sentinelone.com/blogs/analysis-ios-guiinject-adware-library/"

	strings:
		$fat = { CA FE BA BE }

	condition:
		$fat at 0 and uint32( 4 ) < 0x14000000
}

private rule _macho
{
	meta:
		reference = "http://pastebin.com/2W0tyUAF"
		reference2 = "https://sentinelone.com/blogs/analysis-ios-guiinject-adware-library/"

	strings:
		$macho1 = { CE FA ED FE }
		$macho2 = { CF FA ED FE }
		$macho3 = { FE ED FA CE }
		$macho4 = { FE ED FA CF }

	condition:
		for any of ( $macho* ) : ( $ at 0 ) or _fat
}
